solution_code:
#include <stdio.h>
typedef struct { float x; float y; } Point2D;
float manhattan(Point2D a, Point2D b) {
    float dx = a.x - b.x;
    float dy = a.y - b.y;
    if (dx < 0) dx = -dx;
    if (dy < 0) dy = -dy;
    return dx + dy;
}
int main(void) {
    Point2D p1 = {1.0f, 2.0f};
    Point2D p2 = {4.0f, 6.0f};
    printf("p1 = (%.1f, %.1f)\n", p1.x, p1.y);
    printf("p2 = (%.1f, %.1f)\n", p2.x, p2.y);
    printf("Distance Manhattan : %.1f\n", manhattan(p1, p2));
    return 0;
}

